import React, { useRef, useEffect } from 'react';

function extractFramesFromGif(gifSrc) {
    return new Promise((resolve, reject) => {
      const gif = new Image();
      gif.onload = function() {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const frames = [];
  
        canvas.width = gif.width;
        canvas.height = gif.height;
        ctx.drawImage(gif, 0, 0);
  
        const frameCount = gif.naturalWidth / gif.width;
  
        for (let i = 0; i < frameCount; i++) {
          const imageData = ctx.getImageData(i * gif.width, 0, gif.width, gif.height);
          const tempCanvas = document.createElement('canvas');
          const tempCtx = tempCanvas.getContext('2d');
  
          tempCanvas.width = gif.width;
          tempCanvas.height = gif.height;
          tempCtx.putImageData(imageData, 0, 0);
  
          const frameDataURL = tempCanvas.toDataURL('image/png');
          frames.push(frameDataURL);
        }
  
        resolve(frames);
      };
  
      gif.src = gifSrc;
    });
  }
  

function GifAnimationControlledByScroll({ scrollPercentage, src }) {
  const imageRef = useRef(null);

  useEffect(() => {
    const image = imageRef.current;
    image.style.width = '100%'; // Ajusta el ancho de la imagen al 100% del contenedor
    const frameIndex = Math.floor(scrollPercentage * image.naturalWidth);
    image.style.objectPosition = `-${frameIndex}px 0`; // Ajusta la posición del frame según el scrollPercentage
  }, [scrollPercentage, src]);

  return (
    <div className="GifAnimationControlledByScroll">
      <img ref={imageRef} src={src} alt="Animated Image" />
    </div>
  );
}

export default GifAnimationControlledByScroll;
